    setTakeOrderStep("table");
    setTakeOrderVisibleTableCount(15);
    setTakeOrderTableNumber("");
    setTakeOrderSearch("");
    setShowTakeOrderSearch(false);
    setTakeOrderRemarks("");
    setTakeOrderItems([]);
    setShowTakeOrderCart(false);
    setCartDragStartY(null);
    setCartSheetOffsetY(0);
    setEditingOrderId(null);
