                <button
                  type="button"
                  onClick={() => {
                    window.location.href = `/launcher?id=${restaurantId}`;
                  }}
                  className="mt-4 rounded-2xl bg-slate-900 px-4 py-2 text-sm font-semibold text-white"
                >
                  Go to Launcher
                </button>
